}

function mean_absolute_deviation(numbers) {
    if (numbers.length === 0) return 0;

    const sum = numbers.reduce((acc, val) => acc + val, 0);
    const mean = sum / numbers.length;

    const absoluteDeviationsSum = numbers.reduce((acc, val) => acc + Math.abs(val - mean), 0);

    return absoluteDeviationsSum / numbers.length;
}

function intersperse(numbers, delimeter) {
    if (numbers.length === 0) return [];

    const result = [];
    for (let i = 0; i < numbers.length; i++) {
        result.push(numbers[i]);
        if (i < numbers.length - 1) {
            result.push(delimeter);
        }
    }
    return result;
}

function parse_nested_parens(paren_string) {
    return paren_string.split(' ').map(group => {
        let maxDepth = 0;
        let currentDepth = 0;
        for (const char of group) {
            if (char === '(') {
                currentDepth++;
                if (currentDepth > maxDepth) {
                    maxDepth = currentDepth;
                }
            } else if (char === ')') {
                currentDepth--;
            }
        }
        return maxDepth;
    });
}

