function make_palindrome(string) {
    if (string === "") return "";

    const n = string.length;
    let start = 0;

    // Find the longest palindromic suffix
    for (let i = 0; i < n; i++) {
        let left = i;
        let right = n - 1;
        let isPalindrome = true;

        while (left < right) {
            if (string[left] !== string[right]) {
                isPalindrome = false;
                break;
            }
            left++;
            right--;
        }

        if (isPalindrome) {
            start = i;
            break;
        }
    }

    // Get the prefix before the palindromic suffix and reverse it
    const prefix = string.slice(0, start);
    const reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}

