function factorize(n) {
    const factors = [];
    let divisor = 2;
    let num = n;

    while (divisor * divisor <= num) {
        while (num % divisor === 0) {
            factors.push(divisor);
            num = Math.floor(num / divisor);
        }
        divisor++;
    }

    if (num > 1) {
        factors.push(num);
    }

    return factors;
}
