function sort_even(l) {
    const evenIndices = [];
    const evenValues = [];

    // Collect values at even indices and store their original positions
    for (let i = 0; i < l.length; i += 2) {
        evenIndices.push(i);
        evenValues.push(l[i]);
    }

    // Sort the collected even-indexed values
    evenValues.sort((a, b) => a - b);

    // Create a copy of the original array to modify
    const result = [...l];

    // Place sorted values back into their respective even indices
    for (let i = 0; i < evenIndices.length; i++) {
        result[evenIndices[i]] = evenValues[i];
    }

    return result;
}

function prime_fib(n) {
    const isPrime = (num) => {
        if (num < 2) return false;
        if (num === 2) return true;
        if (num % 2 === 0) return false;
        for (let i = 3; i * i <= num; i += 2) {
            if (num % i === 0) return false;
        }
        return true;
    };

    let count = 0;
    let a = 1;
    let b = 1;

    while (true) {
        const fib = a + b;
        if (isPrime(fib)) {
            count++;
            if (count === n) return fib;
        }
        a = b;
        b = fib;
    }
}

