function modp(n, p) {
    if (n === 0) return 1 % p;
    let result = 1;
    let base = 2 % p;
    let exp = n;
    while (exp > 0) {
        if (exp & 1) {
            result = (result * base) % p;
        }
        base = (base * base) % p;
        exp >>>= 1;
    }
    return result;
}

