function circular_shift(x, shift) {
    const s = x.toString();
    const n = s.length;
    if (n === 0) return "";

    let effectiveShift = shift % n;

    if (shift > n) {
        return s.split('').reverse().join('');
    }

    if (effectiveShift === 0) {
        return s;
    }

    const splitIndex = n - effectiveShift;
    return s.slice(splitIndex) + s.slice(0, splitIndex);
}

