function minPath(grid, k) {
    const n = grid.length;
    if (k === 0) return [];

    // Find the position of the minimum value (which is always 1)
    let startRow = -1, startCol = -1;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                startRow = i;
                startCol = j;
                break;
            }
        }
        if (startRow !== -1) break;
    }

    // If k is 1, just return [1]
    if (k === 1) return [1];

    // We need to find the lexicographically smallest path of length k starting from 1.
    // Since we must start at 1 (to be minimal), we perform a BFS/DFS that tracks the path.
    // However, since we want the lexicographically smallest sequence, and the grid values are unique,
    // we can use a greedy approach with BFS level by level, keeping only the best paths at each step.

    // Directions: up, down, left, right
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];

    // Current set of positions we can be at after 'step' moves, along with the path taken.
    // But storing full paths is expensive. Instead, we note that at each step, 
    // we only care about the current position and the fact that we've followed the minimal prefix.
    // However, different paths might lead to the same cell with the same value sequence? 
    // Actually, since all values are unique, the sequence of values uniquely determines the path.
    // But multiple paths could have the same value sequence? No, because values are unique per cell.
    // So if two paths have the same value sequence, they must visit the same cells in the same order.

    // Therefore, at each step, we can maintain a set of current positions that are part of 
    // the lexicographically minimal path(s) so far. Since the answer is unique, there will be only one best path.
    // But during intermediate steps, there might be multiple paths with the same prefix? 
    // Actually, because values are unique, if two paths have the same value sequence, they are the same path.
    // So at each step, we can have multiple candidate positions that yield the same minimal prefix? 
    // No: the prefix is the sequence of values. If two different paths have the same value sequence, 
    // then they must have visited the same cells (since values are unique). So there's only one path per value sequence.

    // However, at step i, we might have multiple candidate next moves that yield the same minimal next value? 
    // But since all values are distinct, the next value in the path is determined by the cell we move to.
    // So if from current set of positions, we can move to several neighbors, we pick the neighbor with the smallest value.
    // But note: we might have multiple current positions (from different paths that happened to have the same prefix? 
    // but again, same prefix implies same path). Actually, at step 0, we start at the cell with 1. Only one position.
    // Then at step 1, we look at neighbors of that cell, and pick the neighbor with the smallest value. 
    // But wait: what if there are two neighbors with the same value? Impossible because all values are distinct.
    // So at each step, from the current single position (because the path is unique so far), we choose the neighbor with the smallest value.

    // However, consider: after step 1, we are at a new cell. Then for step 2, we look at neighbors of that cell (including going back).
    // But note: the problem allows revisiting cells. So from the current cell, we can go to any neighbor (even the one we came from).

    // Therefore, the algorithm is simple:
    // Start at the cell with value 1.
    // For the next k-1 steps, from the current cell, choose the neighbor (up, down, left, right) that has the smallest value.
    // Append that value to the path and move there.

    // Why is this correct? Because at each step, to make the path lexicographically smallest, 
    // we must choose the smallest possible next value. Since the choice at step i does not affect the availability of values at step i+1 
    // (because we can revisit cells and the grid is static), the greedy choice is optimal.

    let path = [1];
    let r = startRow;
    let c = startCol;

    for (let step = 1; step < k; step++) {
        let minVal = Infinity;
        let nextR = -1, nextC = -1;

        for (const [dr, dc] of dirs) {
            const nr = r + dr;
            const nc = c + dc;
            if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                if (grid[nr][nc] < minVal) {
                    minVal = grid[nr][nc];
                    nextR = nr;
                    nextC = nc;
                }
            }
        }

        path.push(minVal);
        r = nextR;
        c = nextC;
    }

    return path;
}

function tri(n) {
    if (n === 0) return [1];

    const result = new Array(n + 1);
    result[0] = 1;
    result[1] = 3;

    for (let i = 2; i <= n; i++) {
        if (i % 2 === 0) {
            result[i] = 1 + i / 2;
        } else {
            // For odd i, we need tri(i-1), tri(i-2), and tri(i+1)
            // Since i is odd, i+1 is even, so we can compute it directly
            const nextEven = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + nextEven;
        }
    }

    return result;
