  if (dotIndex === -1 || dotIndex !== file_name.lastIndexOf('.')) return 'No';

  const namePart = file_name.slice(0, dotIndex);
  const extPart = file_name.slice(dotIndex + 1);

  if (namePart.length === 0) return 'No';
  if (!/[a-zA-Z]/.test(namePart[0])) return 'No';

  const validExtensions = ['txt', 'exe', 'dll'];
  if (!validExtensions.includes(extPart)) return 'No';

