function order_by_points(nums) {
    const sumOfDigits = (n) => {
        let sum = 0;
        n = Math.abs(n);
        if (n === 0) return 0;
        while (n > 0) {
            sum += n % 10;
            n = Math.floor(n / 10);
        }
        return sum;
    };

    const indexed = nums.map((num, index) => ({ num, index, points: sumOfDigits(num) }));

    indexed.sort((a, b) => {
        if (a.points !== b.points) {
            return a.points - b.points;
        }
        return a.index - b.index;
    });

