function get_max_triples(n) {
    if (n < 3) return 0;

    const modCounts = [0, 0, 0]; // counts for remainder 0, 1, 2

    for (let i = 1; i <= n; i++) {
        const val = i * i - i + 1;
        const rem = ((val % 3) + 3) % 3;
        modCounts[rem]++;
    }

    let count = 0;

    // Case 1: All three remainders are 0
    const c0 = modCounts[0];
    if (c0 >= 3) {
        count += (c0 * (c0 - 1) * (c0 - 2)) / 6;
    }

    // Case 2: All three remainders are 1
    const c1 = modCounts[1];
    if (c1 >= 3) {
        count += (c1 * (c1 - 1) * (c1 - 2)) / 6;
    }

    // Case 3: All three remainders are 2
    const c2 = modCounts[2];
    if (c2 >= 3) {
        count += (c2 * (c2 - 1) * (c2 - 2)) / 6;
    }

    // Case 4: One of each remainder (0, 1, 2) -> sum % 3 === 0
    count += c0 * c1 * c2;

    return count;
}

