function make_palindrome(string) {
    if (string === "") return "";

    const n = string.length;

    // Find the longest palindromic suffix
    let i = 0;
    while (i < n) {
        let start = i;
        let end = n - 1;
        let isPalindrome = true;

        while (start < end) {
            if (string[start] !== string[end]) {
                isPalindrome = false;
                break;
            }
            start++;
            end--;
        }

        if (isPalindrome) {
            break;
        }
        i++;
    }

    // The prefix before the palindromic suffix is string[0...i-1]
    const prefix = string.substring(0, i);
    const reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}

