function anti_shuffle(s) {
  const result = [];
  let i = 0;
  while (i < s.length) {
    if (s[i] === ' ') {
      result.push(' ');
      i++;
    } else {
      let start = i;
      while (i < s.length && s[i] !== ' ') {
        i++;
      }
      const word = s.slice(start, i);
      const sortedWord = word.split('').sort((a, b) => a.charCodeAt(0) - b.charCodeAt(0)).join('');
      result.push(sortedWord);
    }
  }
  return result.join('');
}

function get_row(lst, x) {
