    for (let i = 0; i < lst.length; i++) {
        const row = lst[i];
        for (let j = 0; j < row.length; j++) {
            if (row[j] === x) {
                result.push([i, j]);
            }
        }
    }
    result.sort((a, b) => {
        if (a[0] !== b[0]) {
            return a[0] - b[0];
        }
        return b[1] - a[1];
    });
    return result;
}

function sort_array(array) {
    if (array.length === 0) return [];
    const sum = array[0] + array[array.length - 1];
    const isOdd = sum % 2 !== 0;
    const result = [...array];
    if (isOdd) {
        result.sort((a, b) => a - b);
    } else {
        result.sort((a, b) => b - a);
    }
    return result;
}

function encrypt(s) {
  return s.split('').map(char => {
    if (char >= 'a' && char <= 'z') {
      const base = 'a'.charCodeAt(0);
      const shifted = ((char.charCodeAt(0) - base + 4) % 26) + base;
      return String.fromCharCode(shifted);
    } else if (char >= 'A' && char <= 'Z') {
      const base = 'A'.charCodeAt(0);
      const shifted = ((char.charCodeAt(0) - base + 4) % 26) + base;
      return String.fromCharCode(shifted);
    }
    return char;
  }).join('');
}

function next_smallest(lst) {
    if (!Array.isArray(lst) || lst.length < 2) return undefined;

    let smallest = Infinity;
    let secondSmallest = Infinity;

    for (let num of lst) {
        if (num < smallest) {
            secondSmallest = smallest;
            smallest = num;
        } else if (num > smallest && num < secondSmallest) {
            secondSmallest = num;
        }
    }

    return secondSmallest === Infinity ? undefined : secondSmallest;
}

function is_bored(S) {
  if (!S) return 0;

  const delimiters = ['.', '?', '!'];
  let count = 0;
  let currentSentence = '';

  for (let i = 0; i < S.length; i++) {
    const char = S[i];
    currentSentence += char;

    if (delimiters.includes(char)) {
      const trimmed = currentSentence.trim();
      if (trimmed.startsWith('I ')) {
        count++;
      } else if (trimmed === 'I') {
        count++;
      }
      currentSentence = '';
    }
  }

  // Handle the last sentence if it doesn't end with a delimiter
  const trimmedLast = currentSentence.trim();
  if (trimmedLast) {
    if (trimmedLast.startsWith('I ')) {
      count++;
    } else if (trimmedLast === 'I') {
      count++;
    }
  }

  return count;
}

