function encode(message) {
    const vowels = 'aeiouAEIOU';
    const vowelMap = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    };

    return message.split('').map(char => {
        if (vowels.includes(char)) {
            return vowelMap[char];
        }
        if (char >= 'a' && char <= 'z') {
            return char.toUpperCase();
        }
        if (char >= 'A' && char <= 'Z') {
            return char.toLowerCase();
        }
        return char;
    }).join('');
}

