function check_dict_case(dict) {
  const keys = Object.keys(dict);

  if (keys.length === 0) {
    return false;
  }

  let allLower = true;
  let allUpper = true;

  for (const key of keys) {
    if (typeof key !== 'string') {
      return false;
    }

    const isLower = key === key.toLowerCase();
    const isUpper = key === key.toUpperCase();

    if (!isLower) allLower = false;
    if (!isUpper) allUpper = false;
  }

  return allLower || allUpper;
}

