function closest_integer(value) {
    const num = Number(value);
    if (!Number.isFinite(num)) {
        throw new Error("Invalid number");
    }
    const floor = Math.floor(num);
    const ceil = Math.ceil(num);
    if (floor === ceil) {
        return floor;
    }
    const distFloor = Math.abs(num - floor);
    const distCeil = Math.abs(num - ceil);
    if (distFloor < distCeil) {
        return floor;
    } else if (distCeil < distFloor) {
        return ceil;
    } else {
        // Equidistant: round away from zero
        return num > 0 ? ceil : floor;
    }
}

