function minPath(grid, k) {
    const n = grid.length;
    if (k === 0) return [];

    // Find the position of the minimum value (which is always 1)
    let startRow = -1, startCol = -1;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                startRow = i;
                startCol = j;
                break;
            }
        }
        if (startRow !== -1) break;
    }

    // If k is 1, just return [1]
    if (k === 1) return [1];

    const result = [1];
    let currRow = startRow;
    let currCol = startCol;

    // Directions: up, down, left, right
    const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];

    for (let step = 1; step < k; step++) {
        let minVal = Infinity;
        let nextRow = currRow;
        let nextCol = currCol;

        // Check all neighbors
        for (const [dr, dc] of directions) {
            const nr = currRow + dr;
            const nc = currCol + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                if (grid[nr][nc] < minVal) {
                    minVal = grid[nr][nc];
                    nextRow = nr;
                    nextCol = nc;
                } else if (grid[nr][nc] === minVal) {
                    // If values are equal, we need to look ahead to break ties
                    // But since the problem guarantees a unique answer and we're building greedily,
                    // and the grid contains unique numbers 1..N*N, there won't be duplicate values.
                    // So this case is theoretically impossible given the problem constraints.
                }
            }
        }

        result.push(minVal);
        currRow = nextRow;
        currCol = nextCol;
    }

    return result;
}

function tri(n) {
    if (n === 0) return [1];

    const result = new Array(n + 1);
    result[0] = 1;
    result[1] = 3;

    for (let i = 2; i <= n; i++) {
        if (i % 2 === 0) {
            result[i] = 1 + i / 2;
        } else {
            // For odd i, we need tri(i-1), tri(i-2), and tri(i+1)
            // But tri(i+1) is even, so we can compute it directly: 1 + (i+1)/2
            const nextEven = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + nextEven;
        }
    }

    return result;
}

