    // In "[]]]]]]][[[[[]", we have indices: 0='[', 1=']', ... then later many '[' and finally '[]'.
    // Can we pick s[0], s[some later index], s[some later index], s[last]?
    // We need "[ [ ] ]". 
    // s[0] = '['. We need another '[' after it. There are '[' at the end.
    // Then we need a ']' after that second '['. There is a ']' at the very end.
    // Then we need a ']' after that. But there is no ']' after the last ']'? 
    // The string ends with "[]". So indices: ... [ (at n-2), ] (at n-1).
    // If we pick s[0] = '[', then s[n-2] = '[', then s[n-1] = ']'. We need one more ']' to close the first '['.
    // There is no ']' after s[n-1]. So we cannot form "[[]]".

    // Example: "[][]" -> false.
    // We have [ ] [ ]. Can we pick [ [ ] ]? 
    // First [ at 0. Second [ at 2. First ] at 3 (closes second [). Need another ] to close first [. None after 3.
    // So false. Correct.

    // Example: "[[]]" -> true.
    // 0:[, 1:[, 2:], 3:]. Yes.

    // Example: "[[][]]" -> true.
    // 0:[, 1:[, 2:], 3:[, 4:], 5:]. 
    // Pick 0, 1, 2, 5 -> [ [ ] ]. Yes.

    // Example: "[[]][[" -> true.
    // 0:[, 1:[, 2:], 3:], 4:[, 5:[.
    // Pick 0, 1, 2, 3 -> [ [ ] ]. Yes.

    // Logic: We need to find a subsequence of the form "[[]]".
    // This is equivalent to finding an opening bracket, then another opening bracket, 
    // then a closing bracket (for the second), then a closing bracket (for the first).
    // Let's iterate and track state.

    // State 0: Looking for first '['
    // State 1: Found first '[', looking for second '['
    // State 2: Found two '[', looking for first ']' (to close the inner one)
    // State 3: Found "[[]", looking for final ']' (to close the outer one) -> Return true

    let state = 0;
    for (let i = 0; i < s.length; i++) {
        if (s[i] === '[') {
            if (state === 0) state = 1;
            else if (state === 1) state = 2;
            // If state is 2 or 3, we ignore extra '[' because we are looking for specific closing brackets
            // Wait, if we are in state 2 (have [[), and see another '[', does it help?
            // We need to close the inner one. The inner one is the most recent open.
            // Actually, subsequence allows skipping. 
            // If we have "[[[", we can treat the first two as our pair.
            // So if state is 2 or 3, seeing '[' doesn't change our progress towards the specific pattern [ [ ] ].
            // But wait, could a later '[' be better? No, we just need existence.
        } else if (s[i] === ']') {
            if (state === 2) state = 3;
            else if (state === 3) return true;
            // If state is 0 or 1, a ']' doesn't help us start the pattern.
        }
    }

    return false;
}

