    if (!txt || txt.length === 0) return false;

    const lastChar = txt[txt.length - 1];

    // Check if the last character is an alphabetical letter
    if (!/[a-zA-Z]/.test(lastChar)) {
        return false;
    }

    // Check if the last character is part of a word (i.e., preceded by another non-space character)
    // If the string has only one character, it's a word by itself, so we need to check the context
    if (txt.length === 1) {
        return true;
    }

    const secondLastChar = txt[txt.length - 2];

