function do_algebra(operator, operand) {
    const tokens = [];
    for (let i = 0; i < operand.length; i++) {
        tokens.push(operand[i]);
        if (i < operator.length) {
            let op = operator[i];
            if (op === '//') {
                tokens.push('Math.floor');
                tokens.push('(');
            } else if (op === '**') {
                tokens.push('**');
            } else {
                tokens.push(op);
            }
        }
    }

    let expression = '';
    for (let i = 0; i < tokens.length; i++) {
        const token = tokens[i];
        if (token === 'Math.floor') {
            expression += `Math.floor(${tokens[i + 1]} / ${tokens[i + 2]})`;
            i += 3;
            continue;
        } else if (token === '(') {
            continue;
        } else {
            expression += token;
        }
    }

    return Function(`'use strict'; return (${expression})`)();
}

