function how_many_times(string, substring) {
    if (substring.length === 0 || string.length === 0 || substring.length > string.length) {
        return 0;
    }

    let count = 0;
    let index = 0;

    while (index <= string.length - substring.length) {
        const foundIndex = string.indexOf(substring, index);
        if (foundIndex === -1) {
