        'zero': 0,
        'one': 1,
        'two': 2,
        'three': 3,
        'four': 4,
        'five': 5,
        'six': 6,
        'seven': 7,
        'eight': 8,
        'nine': 9
    };

    const words = numbers.split(' ');

    // Filter out empty strings in case of multiple spaces or leading/trailing spaces
    const validWords = words.filter(w => w !== '');

    // Sort based on the numeric value of the words
    validWords.sort((a, b) => {
        return wordToNum[a] - wordToNum[b];
    });

    return validWords.join(' ');
}
```

```javascript
function find_closest_elements(numbers) {
    if (numbers.length < 2) {
        throw new Error("Array must contain at least two elements");
    }

    // Sort the array in ascending order
    const sorted = [...numbers].sort((a, b) => a - b);

    let minDiff = Infinity;
    let closestPair = [sorted[0], sorted[1]];

    for (let i = 0; i < sorted.length - 1; i++) {
        const diff = sorted[i + 1] - sorted[i];
        if (diff < minDiff) {
            minDiff = diff;
            closestPair = [sorted[i], sorted[i + 1]];
        }
    }

    return closestPair;
}
```

