        if (i % 3 === 0) {
            valuesAtDivBy3.push(l[i]);
        }
    }

    // Sort these values
    valuesAtDivBy3.sort((a, b) => a - b);

    // Create the result array
    const l_prime = [...l];
    let idx = 0;
    for (let i = 0; i < l_prime.length; i++) {
