    const evenValues = [];
    for (let i = 0; i < l.length; i += 2) {
        evenValues.push(l[i]);
    }

    // Sort the extracted even-indexed values
    evenValues.sort((a, b) => a - b);

    // Create a copy of the original array
    const result = [...l];

    // Place the sorted values back into even indices
    let evenIndex = 0;
    for (let i = 0; i < result.length; i += 2) {
        result[i] = evenValues[evenIndex];
        evenIndex++;
    }

    return result;
}
