function prime_fib(n) {
    if (n <= 0) return undefined;

    function isPrime(num) {
        if (num < 2) return false;
        if (num === 2) return true;
        if (num % 2 === 0) return false;
        for (let i = 3; i <= Math.sqrt(num); i += 2) {
            if (num % i === 0) return false;
        }
        return true;
    }

    let count = 0;
    let a = 0;
    let b = 1;

    while (true) {
        let fib = a + b;
        a = b;
        b = fib;

        if (isPrime(fib)) {
            count++;
            if (count === n) {
                return fib;
            }
        }
    }
}
