```javascript
function modp(n, p) {
    if (n === 0) return 1 % p;

    let result = 1;
    let base = 2n;
    let exp = BigInt(n);
    let mod = BigInt(p);

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp = exp / 2n;
    }

    return Number(result);
}
