```javascript
function largest_prime_factor(n) {
    let largest = -1;

    // Divide out all factors of 2
    while (n % 2 === 0) {
        largest = 2;
        n /= 2;
    }

    // Now n must be odd. Check odd numbers starting from 3.
    for (let i = 3; i * i <= n; i += 2) {
        while (n % i === 0) {
            largest = i;
            n /= i;
        }
    }

    // If n is still greater than 1, then the remaining n is a prime factor
    if (n > 1) {
        largest = n;
    }

    return largest;
}
