```javascript
function circular_shift(x, shift) {
    const s = String(x);
    const n = s.length;

    if (n === 0) return "";

    if (shift > n) {
        return s.split('').reverse().join('');
    }

    const effectiveShift = shift % n;
    if (effectiveShift === 0) {
        return s;
    }

    const rightPart = s.slice(n - effectiveShift);
    const leftPart = s.slice(0, n - effectiveShift);

    return rightPart + leftPart;
}
