function is_simple_power(x, n) {
    if (n === 0) {
        return x === 1; // 0^k = 0 for k>0, but 0^0 is undefined/1. Usually 0^n=0. If x=1, no integer power of 0 gives 1 except maybe 0^0 which is debatable. Let's look at constraints.
        // Actually, if n=0, then 0**int = 0 for any positive int. 0**0 is often 1.
        // The problem says n**int = x.
        // If n=0 and x=1, is there an integer k such that 0^k = 1? No, unless k=0 and we define 0^0=1.
        // If n=0 and x=0, is there an integer k such that 0^k = 0? Yes, any k >= 1.
        // Let's handle edge cases carefully.
    }

    if (n === 1) {
        return x === 1; // 1**k = 1 for any k. So only x=1 is a simple power of 1.
    }

    if (n === -1) {
        // (-1)**k = 1 if k is even, -1 if k is odd.
        return x === 1 || x === -1;
    }

    // For other n, we can try to find an integer k such that n^k = x.
    // We can iterate through possible values of k.
    // Since x and n are numbers, we need to consider the magnitude.
    // If |n| > 1, then |x| grows exponentially with k.
    // We can start with k=0, 1, 2, ... until n^k exceeds |x|.

    let current = 1;
    for (let k = 0; ; k++) {
        if (current === x) {
            return true;
        }
        // If we've exceeded the magnitude of x and n is not 1 or -1, we can stop.
        // But we need to be careful with negative numbers and zero.

        // Calculate next power
        let next = current * n;

        // Check if we're diverging away from x
        // If |n| > 1, the powers will grow in magnitude.
        // If |n| < 1 (and n != 0), the powers will shrink towards 0.
        // But the problem likely implies integer bases and results.

        // Let's just iterate a reasonable number of times or until we overshoot.
        // A simple approach: if |current| > |x| and |n| > 1, we can stop.
        // However, for negative n, the sign alternates.

        // Better approach: use logarithms?
        // k = log_n(x) = ln(x)/ln(n). Check if this is an integer.
        // This works for positive x and n > 1.

        // Let's stick to iteration for robustness with integers.
        // We need a stopping condition.
        // If |n| >= 2, then |n^k| grows exponentially.
        // If |x| is large, we might need many iterations, but typically x fits in a number.

        // Special case: if n=0, handled above? No, let's re-evaluate n=0.
        // If n=0:
        //   k=0: 0^0 = 1 (by convention in many contexts, or undefined). Let's assume 0^0=1 for this problem if it matches x=1.
        //   k>=1: 0^k = 0.
        // So if n=0, return true if x===1 or x===0.

        // Let's refine the loop.
        if (Math.abs(n) > 1) {
            if (Math.abs(current) > Math.abs(x)) {
                break;
            }
        } else if (n === 0) {
            // If n=0, we already handled it? No, let's handle it in the loop or before.
            // If n=0, current starts at 1 (k=0). Next is 0 (k=1). Next is 0 (k=2)...
            // So if x=1, k=0 works. If x=0, k>=1 works.
            // The loop will catch x=1 at k=0. Then next=0. If x=0, it will match at k=1.
            // But we need to avoid infinite loops for n=0 if x is not 0 or 1.
            // If n=0 and x is not 0 or 1, we should break after checking a few values.
        } else if (n === -1) {
            // Handled above.
        } else {
            // |n| < 1 and n != 0. This means n is a fraction like 0.5.
            // Then n^k approaches 0 as k increases.
            // We should stop when current becomes very small or equals x.
            if (Math.abs(current) < 1e-9 && Math.abs(x) > 1e-9) {
                break;
            }
        }

        current = next;

        // Safety break for infinite loops
        if (k > 1000) {
            break;
        }
    }

    return false;
}
