        return num;
    }

    const distToFloor = Math.abs(num - floor);
    const distToCeil = Math.abs(num - ceil);

    if (distToFloor < distToCeil) {
        return floor;
    } else if (distToCeil < distToFloor) {
        return ceil;
    } else {
