            // Among -2, -3: decimal order is -3, -2
            // So result would be [-6, -5, -4, -3, -2] which matches the example!

            // So we need to count ones in the 32-bit two's complement representation.
            let count = 0;
            let num = n >>> 0; // Convert to unsigned 32-bit integer
            while (num) {
