function intersection(interval1, interval2) {
    const start1 = interval1[0];
    const end1 = interval1[1];
    const start2 = interval2[0];
    const end2 = interval2[1];

    // Calculate the intersection boundaries
    const interStart = Math.max(start1, start2);
    const interEnd = Math.min(end1, end2);

    // If there is no intersection
    if (interStart > interEnd) {
        return "NO";
    }

    // The length of the intersection interval [interStart, interEnd]
    // Since it's a closed interval, the number of integers is (end - start + 1).
    // However, looking at the example:
    // (1, 3) and (2, 4) -> intersection (2, 3).
    // The problem states "length" is 1.
    // Usually length of interval [a, b] is b - a.
    // Let's check: 3 - 2 = 1. Correct.
    // Example 2: [-1, 1], [0, 4] -> intersection [0, 1]. Length = 1 - 0 = 1. Not prime. "NO". Correct.
    // Example 3: [-3, -1], [-5, 5] -> intersection [-3, -1]. Length = -1 - (-3) = 2. Prime. "YES". Correct.

    const length = interEnd - interStart;

    if (length < 2) {
        return "NO";
    }

    // Check if length is prime
    for (let i = 2; i <= Math.sqrt(length); i++) {
        if (length % i === 0) {
            return "NO";
        }
    }

    return "YES";
}
