function tri(n) {
    if (n < 0) return [];

    // We need to compute the first n+1 numbers of the Tribonacci sequence.
    // The sequence is indexed from 0 to n.
    // Let's define an array `result` where result[i] = tri(i).

    const result = new Array(n + 1);

    // Base case: tri(0) = 1 (from the example tri(3) returns [1, 3, 2, 8], so index 0 is 1)
    // Wait, let's check the examples carefully.
    // tri(3) returns [1, 3, 2, 8]
    // Index 0: 1
    // Index 1: 3 -> tri(1) = 3 (given)
    // Index 2: 2 -> tri(2) = 1 + 2/2 = 2 (given)
    // Index 3: 8 -> tri(3) = tri(2) + tri(1) + tri(4) = 2 + 3 + 3 = 8

    // So tri(0) is not explicitly defined in the recurrence but from the example, result[0] = 1.
    // Let's assume tri(0) = 1.

    if (n >= 0) {
        result[0] = 1;
    }
    if (n >= 1) {
        result[1] = 3;
    }

    for (let i = 2; i <= n; i++) {
        if (i % 2 === 0) {
            // i is even
            result[i] = 1 + i / 2;
        } else {
            // i is odd
            // tri(i) = tri(i-1) + tri(i-2) + tri(i+1)
            // But tri(i+1) depends on whether i+1 is even or odd.
            // Since i is odd, i+1 is even.
            // So tri(i+1) = 1 + (i+1)/2
            // Therefore: tri(i) = tri(i-1) + tri(i-2) + (1 + (i+1)/2)

            const tri_i_plus_1 = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + tri_i_plus_1;
        }
    }

    return result;
}
