function order_by_points(nums) {
    if (nums.length === 0) return [];

    // Helper function to calculate sum of digits
    function digitSum(n) {
        // Handle negative numbers by taking absolute value
        let num = Math.abs(n);
        if (num === 0) return 0;

        let sum = 0;
        while (num > 0) {
            sum += num % 10;
            num = Math.floor(num / 10);
        }
        return sum;
    }

    // Create an array of objects with original index, value, and digit sum
    let indexedNums = nums.map((num, index) => ({
        value: num,
        index: index,
        sum: digitSum(num)
    }));

    // Sort by digit sum ascending, then by original index ascending for ties
    indexedNums.sort((a, b) => {
        if (a.sum !== b.sum) {
            return a.sum - b.sum;
        } else {
            return a.index - b.index;
        }
    });

    // Extract the sorted values
    return indexedNums.map(item => item.value);
}
