```javascript
function get_max_triples(n) {
    // Calculate the array a where a[i] = i*i - i + 1 for i from 1 to n
    // We need to count triples (i, j, k) with 1 <= i < j < k <= n
    // such that a[i] + a[j] + a[k] is divisible by 3.

    // Let's analyze a[i] mod 3.
    // a[i] = i^2 - i + 1
    // Let's compute a[i] % 3 for i = 1, 2, 3, ...
    // i=1: 1 - 1 + 1 = 1 -> 1 % 3 = 1
    // i=2: 4 - 2 + 1 = 3 -> 3 % 3 = 0
    // i=3: 9 - 3 + 1 = 7 -> 7 % 3 = 1
    // i=4: 16 - 4 + 1 = 13 -> 13 % 3 = 1
    // i=5: 25 - 5 + 1 = 21 -> 21 % 3 = 0
    // i=6: 36 - 6 + 1 = 31 -> 31 % 3 = 1
    // i=7: 49 - 7 + 1 = 43 -> 43 % 3 = 1
    // i=8: 64 - 8 + 1 = 57 -> 57 % 3 = 0

    // Pattern of a[i] % 3 for i=1,2,3,...:
    // i mod 3 = 1: i=1,4,7,... -> a[i] % 3 = 1
    // i mod 3 = 2: i=2,5,8,... -> a[i] % 3 = 0
    // i mod 3 = 0: i=3,6,9,... -> a[i] % 3 = 1

    // So:
    // If i % 3 == 1 or i % 3 == 0, then a[i] % 3 = 1
    // If i % 3 == 2, then a[i] % 3 = 0

    // Let's verify:
    // i=1: 1%3=1 -> a[1]%3=1 ✓
    // i=2: 2%3=2 -> a[2]%3=0 ✓
    // i=3: 3%3=0 -> a[3]%3=1 ✓
    // i=4: 4%3=1 -> a[4]%3=1 ✓
    // i=5: 5%3=2 -> a[5]%3=0 ✓

    // So we have two types of residues:
    // Type 0 (residue 0): when i % 3 == 2
    // Type 1 (residue 1): when i % 3 == 0 or i % 3 == 1

    // We need a[i] + a[j] + a[k] ≡ 0 (mod 3)
    // Possible combinations of residues (r1, r2, r3) where r1+r2+r3 ≡ 0 mod 3:
    // - (0, 0, 0): sum = 0
    // - (1, 1, 1): sum = 3 ≡ 0
    // - (0, 1, ?): need third to be 2, but we don't have residue 2. So no mixed cases with 0 and 1 work unless...
    // Wait, let me re-check. Residues are only 0 and 1.
    // 0+0+0 = 0 ✓
    // 0+0+1 = 1 ✗
    // 0+1+1 = 2 ✗
    // 1+1+1 = 3 ≡ 0 ✓

    // So only two cases: all three have residue 0, or all three have residue 1.

    // Count how many indices i in [1, n] have a[i] % 3 == 0 (call this count0)
    // and how many have a[i] % 3 == 1 (call this count1).

    // Indices with residue 0: i % 3 == 2, i.e., i = 2, 5, 8, ...
    // This is an arithmetic sequence: 2, 5, 8, ..., up to n.
    // Number of terms: floor((n - 2) / 3) + 1 if n >= 2, else 0.
    // More precisely: count0 = Math.floor((n + 1) / 3) ... let me check.
    // For n=5: indices 2, 5 -> count0 = 2. (5+1)/3 = 2. ✓
    // For n=4: indices 2 -> count0 = 1. (4+1)/3 = 1.66... floor = 1. ✓
    // For n=2: indices 2 -> count0 = 1. (2+1)/3 = 1. ✓
    // For n=1: no indices -> count0 = 0. (1+1)/3 = 0.66... floor = 0. ✓
    // So count0 = Math.floor((n + 1) / 3)

    // Indices with residue 1: i % 3 == 0 or i % 3 == 1, i.e., i = 1, 3, 4, 6, 7, ...
    // count1 = n - count0

    // Number of triples with all residue 0: C(count0, 3) = count0 * (count0-1) * (count0-2) / 6
    // Number of triples with all residue 1: C(count1, 3) = count1 * (count1-1) * (count1-2) / 6

    const count0 = Math.floor((n + 1) / 3);
    const count1 = n - count0;

    function combinationsOf3(k) {
        if (k < 3) return 0;
        return k * (k - 1) * (k - 2) / 6;
    }

    return combinationsOf3(count0) + combinationsOf3(count1);
}
