    let maxUniqueCount = -1;

    for (const word of words) {
        const uniqueChars = new Set(word);
        const uniqueCount = uniqueChars.size;

        if (uniqueCount > maxUniqueCount) {
            maxUniqueCount = uniqueCount;
            bestWord = word;
