function make_palindrome(string) {
    if (string === "") return "";

    // Find the longest postfix of string that is a palindrome
    let start = 0;
    let end = string.length - 1;
    let longestPalindromeStart = 0;

    // Check each possible starting position for a palindromic suffix
    // A palindromic suffix starts at index i and goes to the end
    for (let i = 0; i < string.length; i++) {
        if (isPalindrome(string, i, string.length - 1)) {
            longestPalindromeStart = i;
            break;
        }
    }

    // The prefix before the palindromic suffix is from 0 to longestPalindromeStart - 1
    const prefix = string.substring(0, longestPalindromeStart);
    const reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}

function isPalindrome(str, start, end) {
    while (start < end) {
        if (str[start] !== str[end]) {
            return false;
        }
        start++;
        end--;
    }
    return true;
}
