function starts_one_ends(n) {
    if (n === 1) {
        return 1;
    }

    // Count of n-digit numbers that start with 1
    // First digit is 1, remaining n-1 digits can be anything (0-9)
    const startsWith1 = Math.pow(10, n - 1);

    // Count of n-digit numbers that end with 1
    // Last digit is 1, first digit can be 1-9 (9 choices), remaining n-2 digits can be anything (0-9)
    const endsWith1 = 9 * Math.pow(10, n - 2);

    // Count of n-digit numbers that both start and end with 1
    // First digit is 1, last digit is 1, remaining n-2 digits can be anything (0-9)
    const startsAndEndsWith1 = Math.pow(10, n - 2);

    // Using inclusion-exclusion principle
    return startsWith1 + endsWith1 - startsAndEndsWith1;
}
