```function closest_integer(value) {
    const num = parseFloat(value);
    const floor = Math.floor(num);
    const ceil = Math.ceil(num);

    // If it's already an integer
    if (num === floor) {
        return num;
    }

    const distToFloor = Math.abs(num - floor);
    const distToCeil = Math.abs(num - ceil);

    if (distToFloor < distToCeil) {
        return floor;
    } else if (distToCeil < distToFloor) {
        return ceil;
    } else {
        // Equidistant: round away from zero
        if (num > 0) {
            return ceil;
        } else {
            return floor;
        }
    }
}
