function exchange(lst1, lst2) {
    // Count how many odd numbers are in lst1 (these need to be replaced)
    let oddCountInLst1 = 0;
    for (let num of lst1) {
        if (num % 2 !== 0) {
            oddCountInLst1++;
        }
    }

    // If there are no odd numbers in lst1, it's already all even
    if (oddCountInLst1 === 0) {
        return "YES";
    }

    // Count how many even numbers are in lst2 (these can be used to replace odds in lst1)
    let evenCountInLst2 = 0;
    for (let num of lst2) {
        if (num % 2 === 0) {
            evenCountInLst2++;
        }
    }

    // We need at least as many even numbers in lst2 as there are odd numbers in lst1
    if (evenCountInLst2 >= oddCountInLst1) {
        return "YES";
    } else {
        return "NO";
    }
}
