function sort_array(arr) {
    return arr.slice().sort((a, b) => {
        const countOnes = (n) => {
            // For negative numbers, we need to handle them appropriately.
            // The problem states "non-negative integers" in the description but examples include negatives.
            // Looking at the example: sort_array([-2, -3, -4, -5, -6]) returns [-6, -5, -4, -3, -2]
            // Let's analyze the binary representation of negative numbers in JavaScript.
            // JavaScript uses 32-bit signed integers for bitwise operations.
            // -1 is 0xFFFFFFFF (32 ones)
            // -2 is 0xFFFFFFFE (31 ones)
            // -3 is 0xFFFFFFFD (31 ones)
            // -4 is 0xFFFFFFFC (30 ones)
            // -5 is 0xFFFFFFFB (30 ones)
            // -6 is 0xFFFFFFF8 (29 ones)

            // If we count ones using bitwise operations:
            // (-1 >>> 0).toString(2).split('1').length - 1 = 32
            // (-2 >>> 0).toString(2).split('1').length - 1 = 31
            // etc.

            // For the example [-2, -3, -4, -5, -6]:
            // -6: 29 ones
            // -5: 30 ones
            // -4: 30 ones
            // -3: 31 ones
            // -2: 31 ones

            // Sorted by number of ones ascending:
            // -6 (29), then -5 and -4 (30 each), then -3 and -2 (31 each)
            // For ties, sort by decimal value:
            // -5 vs -4: -5 < -4, so -5 comes first
            // -3 vs -2: -3 < -2, so -3 comes first
            // Result: [-6, -5, -4, -3, -2] which matches the expected output!

            const unsigned = n >>> 0;
            let count = 0;
            let temp = unsigned;
            while (temp) {
                count += temp & 1;
                temp >>>= 1;
            }
            return count;
        };

        const onesA = countOnes(a);
        const onesB = countOnes(b);

        if (onesA !== onesB) {
            return onesA - onesB;
        } else {
            return a - b;
        }
    });
}
