    // u is at index 3. Left neighbor: g (consonant), Right neighbor: r (consonant). So u is between two consonants.
    // "Closest from the right" usually implies the one with the highest index. 
    // In "yogurt", u (index 3) is closer to the right end than o (index 1). So return "u".

    // "FULL" -> "U". F-U-L-L. U is at index 1. Left: F (consonant), Right: L (consonant). Return "U".

    // "quick" -> "". q-u-i-c-k. 
    // u at index 1. Left: q (consonant), Right: i (vowel). Not between two consonants.
    // i at index 2. Left: u (vowel), Right: c (consonant). Not between two consonants.
    // Return "".

    // "ab" -> "". a is at start, b is at end. No vowel between two consonants.

    // So the algorithm is:
    // 1. Iterate from right to left (or find all valid vowels and pick the rightmost).
    // 2. A vowel at index i is valid if:
    //    - It is not at the beginning (i > 0)
    //    - It is not at the end (i < word.length - 1)
    //    - The character at i-1 is a consonant (not a vowel)
    //    - The character at i+1 is a consonant (not a vowel)
    // 3. Return the first one found when iterating from right to left, or empty string if none.

    for (let i = word.length - 2; i >= 1; i--) {
        const char = word[i];
        if (vowels.has(char)) {
            const leftChar = word[i - 1];
            const rightChar = word[i + 1];

            // Check if left and right are consonants (i.e., not vowels)
            // Note: The problem says "English letter only", so we don't need to worry about non-letters.
            // A consonant is a letter that is not a vowel.
            const leftIsConsonant = !vowels.has(leftChar);
            const rightIsConsonant = !vowels.has(rightChar);

            if (leftIsConsonant && rightIsConsonant) {
                return char;
            }
        }
    }

    return "";
