function intersection(interval1, interval2) {
    const start = Math.max(interval1[0], interval2[0]);
    const end = Math.min(interval1[1], interval2[1]);

    if (start > end) {
        return "NO";
    }

    const length = end - start + 1;

    if (length < 2) {
        return "NO";
    }

    for (let i = 2; i <= Math.sqrt(length); i++) {
        if (length % i === 0) {
            return "NO";
        }
    }

    return "YES";
}
