function prod_signs(arr) {
    if (arr.length === 0) {
        return undefined;
    }

    let sumMagnitudes = 0;
    let productSigns = 1;

    for (let i = 0; i < arr.length; i++) {
        const num = arr[i];
        sumMagnitudes += Math.abs(num);

        if (num > 0) {
            productSigns *= 1;
        } else if (num < 0) {
            productSigns *= -1;
        } else {
            productSigns *= 0;
        }
    }

    return sumMagnitudes * productSigns;
}
