function minPath(grid, k) {
    const n = grid.length;

    // Find the starting cell with the minimum value.
    // Since we want the lexicographically smallest path of length k,
    // the first element should be as small as possible.
    // The global minimum in the grid is 1. So we start at the cell containing 1.
    let startRow = -1, startCol = -1;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                startRow = i;
                startCol = j;
                break;
            }
        }
        if (startRow !== -1) break;
    }

    // We need to find the lexicographically smallest path of length k starting from (startRow, startCol).
    // This is equivalent to finding the shortest path in a state space where states are (row, col, stepsTaken),
    // but since we want lexicographical order, we can use a BFS-like approach or simply greedy with backtracking?
    // Actually, since k can be large, we need an efficient way.
    // However, note that at each step, we choose the neighbor with the smallest value.
    // But this greedy choice might not lead to the globally lexicographically smallest path because
    // a slightly larger value now might allow much smaller values later.
    // 
    // Wait, let's reconsider. The problem is to find the lexicographically smallest sequence of length k.
    // This is a classic problem that can be solved with BFS/DFS with pruning or using a priority queue.
    // But since the grid size N is not specified to be small, and k can be up to N*N, we need to be careful.
    // 
    // Actually, let's think about it differently. We want the lexicographically smallest path.
    // We can use a modified Dijkstra or BFS where we keep track of the best path to each state (row, col) at each step.
    // But the state space is N*N*k which could be large.
    // 
    // Alternative approach: Since we want the lexicographically smallest path, we can build the path step by step.
    // At step 0, we must start at the cell with value 1 (the global minimum).
    // At step 1, we choose among neighbors of the current cell the one with the smallest value.
    // But wait, if there are multiple neighbors with the same smallest value, which one to choose?
    // We need to look ahead. This suggests that a simple greedy doesn't work.
    // 
    // Let's use BFS with a priority queue (min-heap) where each element is (path_so_far, current_row, current_col).
    // But storing the entire path in the heap is expensive.
    // 
    // Better approach: Use dynamic programming or memoization.
    // Let dp[step][row][col] = the lexicographically smallest suffix of length (k - step) starting from (row, col).
    // But comparing paths lexicographically is expensive.
    // 
    // Given the constraints are not specified, let's assume N is small (e.g., N <= 10) and k is reasonable.
    // We can use DFS with memoization or iterative deepening.
    // 
    // Actually, a simpler approach: since we want the lexicographically smallest path, we can generate all paths of length k
    // starting from the minimum cell and pick the smallest. But this is exponential.
    // 
    // Let's try a different strategy: at each step, among all possible current positions (after t steps),
    // choose the one that leads to the lexicographically smallest next value. If there are ties, we need to keep all tied paths.
    // This is essentially BFS where at each level, we keep only the "best" paths.
    // 
    // Implementation:
    // Let candidates be a list of (path, row, col). Initially, candidates = [([1], startRow, startCol)].
    // For step from 1 to k-1:
    //   next_candidates = []
    //   For each (path, r, c) in candidates:
    //     For each neighbor (nr, nc) of (r, c):
    //       new_path = path + [grid[nr][nc]]
    //       next_candidates.append((new_path, nr, nc))
    //   Sort next_candidates by path lexicographically.
    //   Keep only the candidates with the smallest path prefix. But how many to keep?
    //   We need to keep all candidates that have the same best prefix so far, because they might diverge later.
    //   Actually, we can prune: if two candidates are at the same (row, col) and one's path is lexicographically <= the other's,
    //   then the other can be discarded. But paths of the same length to the same cell... 
    //   Wait, if we're at step t, and we have two paths P1 and P2 ending at (r, c), and P1 < P2 lexicographically,
    //   then for any continuation, P1 + suffix < P2 + suffix. So we can discard P2.
    //   So at each step, for each cell (r, c), we only need to keep the lexicographically smallest path that reaches it.
    // 
    // Algorithm:
    // Let best[r][c] = the lexicographically smallest path of length (step+1) ending at (r, c).
    // Initialize: best[startRow][startCol] = [1], and best[r][c] = null for others.
    // For step from 1 to k-1:
    //   new_best = array of nulls
    //   For each (r, c) where best[r][c] is not null:
    //     For each neighbor (nr, nc):
    //       candidate_path = best[r][c].concat([grid[nr][nc]])
    //       If new_best[nr][nc] is null or candidate_path < new_best[nr][nc]:
    //         new_best[nr][nc] = candidate_path
    //   best = new_best
    // After k-1 steps, find the lexicographically smallest path among all best[r][c].

    // However, storing full paths in best[r][c] might be memory intensive if k is large.
    // But since we only store one path per cell at each step, and there are N*N cells, it's O(N^2 * k) space.
    // Given N >= 2 and no upper bound specified, let's hope N is small.

    // Let's implement this.

    // Initialize best paths: a 2D array where each entry is either null or an array representing the path.
    let best = Array.from({length: n}, () => Array(n).fill(null));
    best[startRow][startCol] = [grid[startRow][startCol]];

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    for (let step = 1; step < k; step++) {
        let new_best = Array.from({length: n}, () => Array(n).fill(null));

        for (let r = 0; r < n; r++) {
            for (let c = 0; c < n; c++) {
                if (best[r][c] === null) continue;

                for (const [dr, dc] of directions) {
                    const nr = r + dr;
                    const nc = c + dc;

                    if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                        const candidate_path = best[r][c].concat([grid[nr][nc]]);

                        if (new_best[nr][nc] === null || isLexicographicallySmaller(candidate_path, new_best[nr][nc])) {
                            new_best[nr][nc] = candidate_path;
                        }
                    }
                }
            }
        }

        best = new_best;
    }

    // Find the lexicographically smallest path among all cells
    let result = null;
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            if (best[r][c] !== null) {
                if (result === null || isLexicographicallySmaller(best[r][c], result)) {
                    result = best[r][c];
                }
            }
        }
    }

    return result;
}

function isLexicographicallySmaller(a, b) {
    const len = Math.min(a.length, b.length);
    for (let i = 0; i < len; i++) {
        if (a[i] < b[i]) return true;
        if (a[i] > b[i]) return false;
    }
    // If all compared elements are equal, the shorter one is smaller.
    // But in our case, both paths have the same length (step+1), so this shouldn't happen.
    return a.length < b.length;
}
