function tri(n) {
    if (n < 0) return [];

    // We need to compute the first n + 1 numbers of the Tribonacci sequence.
    // The sequence is indexed from 0 to n.
    // Let's define an array result where result[i] = tri(i).

    const result = new Array(n + 1);

    // Base case: tri(0) is not explicitly defined in the problem statement for odd/even rules,
    // but looking at the example: tri(3) returns [1, 3, 2, 8]
    // Index 0: 1
    // Index 1: 3 (tri(1) = 3)
    // Index 2: 2 (tri(2) = 1 + 2/2 = 2)
    // Index 3: 8 (tri(3) = tri(2) + tri(1) + tri(4))

    // So tri(0) = 1. Let's verify with the rules:
    // The problem says:
    // tri(1) = 3
    // tri(n) = 1 + n / 2, if n is even.
    // tri(n) = tri(n - 1) + tri(n - 2) + tri(n + 1), if n is odd.

    // For n=0: 0 is even, so tri(0) = 1 + 0/2 = 1. That matches!

    for (let i = 0; i <= n; i++) {
        if (i === 1) {
            result[i] = 3;
        } else if (i % 2 === 0) {
            // Even case
            result[i] = 1 + i / 2;
        } else {
            // Odd case: tri(n) = tri(n - 1) + tri(n - 2) + tri(n + 1)
            // This requires tri(n + 1), which might not be computed yet.
            // We need to handle this carefully.

            // For odd i, we need result[i-1], result[i-2], and result[i+1].
            // result[i+1] is even (since i is odd, i+1 is even), so it can be computed directly: 1 + (i+1)/2

            const triNext = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + triNext;
        }
    }

    return result;
}
