function file_name_check(file_name) {
    // Check if there is exactly one dot
    const dotCount = (file_name.match(/\./g) || []).length;
    if (dotCount !== 1) {
        return 'No';
    }

    const parts = file_name.split('.');
    const namePart = parts[0];
    const extensionPart = parts[1];

    // Check if the substring before the dot is not empty
    if (namePart.length === 0) {
        return 'No';
    }

    // Check if the substring before the dot starts with a letter from the latin alphabet
    if (!/^[a-zA-Z]/.test(namePart)) {
        return 'No';
    }

    // Check if there are not more than three digits in the file's name
    const digitCount = (file_name.match(/[0-9]/g) || []).length;
    if (digitCount > 3) {
        return 'No';
    }

    // Check if the substring after the dot is one of ['txt', 'exe', 'dll']
    if (!['txt', 'exe', 'dll'].includes(extensionPart)) {
        return 'No';
    }

    return 'Yes';
}
