function get_max_triples(n) {
    // Calculate the array a where a[i] = i*i - i + 1 for i from 1 to n
    // We need to count triples (i, j, k) with 1 <= i < j < k <= n
    // such that a[i] + a[j] + a[k] is divisible by 3.

    // Let's analyze a[i] mod 3.
    // a[i] = i^2 - i + 1
    // Let's compute a[i] % 3 for i = 1, 2, 3, ...
    // i=1: 1 - 1 + 1 = 1 => 1 % 3 = 1
    // i=2: 4 - 2 + 1 = 3 => 3 % 3 = 0
    // i=3: 9 - 3 + 1 = 7 => 7 % 3 = 1
    // i=4: 16 - 4 + 1 = 13 => 13 % 3 = 1
    // i=5: 25 - 5 + 1 = 21 => 21 % 3 = 0
    // i=6: 36 - 6 + 1 = 31 => 31 % 3 = 1
    // i=7: 49 - 7 + 1 = 43 => 43 % 3 = 1
    // i=8: 64 - 8 + 1 = 57 => 57 % 3 = 0

    // Let's check the pattern of i^2 - i + 1 mod 3.
    // i mod 3 = 0: i^2 - i + 1 = 0 - 0 + 1 = 1 mod 3? Wait, let me recalculate.
    // If i ≡ 0 (mod 3): i^2 ≡ 0, i ≡ 0, so i^2 - i + 1 ≡ 0 - 0 + 1 ≡ 1 (mod 3)
    // If i ≡ 1 (mod 3): i^2 ≡ 1, i ≡ 1, so i^2 - i + 1 ≡ 1 - 1 + 1 ≡ 1 (mod 3)
    // If i ≡ 2 (mod 3): i^2 ≡ 4 ≡ 1, i ≡ 2, so i^2 - i + 1 ≡ 1 - 2 + 1 ≡ 0 (mod 3)

    // So:
    // a[i] % 3 = 1 if i % 3 != 2
    // a[i] % 3 = 0 if i % 3 == 2

    // Let's verify with the example:
    // i=1: 1%3=1, so a[1]%3=1. Correct (a[1]=1).
    // i=2: 2%3=2, so a[2]%3=0. Correct (a[2]=3).
    // i=3: 3%3=0, so a[3]%3=1. Correct (a[3]=7, 7%3=1).
    // i=4: 4%3=1, so a[4]%3=1. Correct (a[4]=13, 13%3=1).
    // i=5: 5%3=2, so a[5]%3=0. Correct (a[5]=21, 21%3=0).

    // So the residues are:
    // For i from 1 to n:
    //   if i % 3 == 2, residue is 0
    //   otherwise, residue is 1

    // We need a[i] + a[j] + a[k] ≡ 0 (mod 3).
    // Since residues are only 0 or 1, let's see which combinations sum to 0 mod 3:
    // - 0 + 0 + 0 = 0 ✓
    // - 0 + 0 + 1 = 1 ✗
    // - 0 + 1 + 1 = 2 ✗
    // - 1 + 1 + 1 = 3 ≡ 0 ✓

    // So we need either:
    // Case 1: All three residues are 0.
    // Case 2: All three residues are 1.

    // Let's count how many indices i in [1, n] have residue 0 and how many have residue 1.
    // Residue 0 when i % 3 == 2.
    // Residue 1 when i % 3 != 2 (i.e., i % 3 == 0 or i % 3 == 1).

    let count0 = 0; // number of indices with residue 0
    let count1 = 0; // number of indices with residue 1

    for (let i = 1; i <= n; i++) {
        if (i % 3 === 2) {
            count0++;
        } else {
            count1++;
        }
    }

    // Number of ways to choose 3 indices with residue 0: C(count0, 3)
    // Number of ways to choose 3 indices with residue 1: C(count1, 3)

    function combinations(n, k) {
        if (n < k) return 0;
        let result = 1;
        for (let i = 0; i < k; i++) {
            result = result * (n - i) / (i + 1);
        }
        return Math.round(result); // Should be integer
    }

    const triples0 = combinations(count0, 3);
    const triples1 = combinations(count1, 3);

    return triples0 + triples1;
}
