```javascript
function do_algebra(operator, operand) {
    // Build the expression string by interleaving operands and operators
    let expression = operand[0];
    for (let i = 0; i < operator.length; i++) {
        expression += ' ' + operator[i] + ' ' + operand[i + 1];
    }

    // Replace floor division operator with a custom implementation since JS doesn't have //
    // We need to handle precedence correctly. 
    // Standard JS operators: +, -, *, **, / (but we want floor division)
    // The issue is that eval() will use standard division for /.
    // To handle floor division correctly with proper precedence, we can replace // with a function call or use a custom evaluator.
    // However, the problem states "Floor division ( // )". In Python, // has the same precedence as / and *.
    // In JS, we can simulate this by replacing // with Math.floor(a/b) but that breaks simple string eval.

    // A safer approach is to parse and evaluate respecting operator precedence manually or use a library.
    // Since we can't use libraries, let's implement a simple recursive descent parser or use shunting-yard algorithm.

    // Operators and their precedence:
    // ** : 3 (right associative)
    // *, /, // : 2 (left associative)
    // +, - : 1 (left associative)

    // Let's convert the infix expression to postfix (RPN) using shunting-yard algorithm, then evaluate.

    const tokens = [];
    // Split the expression into numbers and operators
    // The expression is built from integers and operators.
    // We can split by spaces if we added them, but let's just parse carefully.
    // Actually, since operands are non-negative integers, we can tokenize easily.

    // Re-tokenize from operator and operand arrays directly to avoid string parsing issues
    const infixTokens = [];
    for (let i = 0; i < operand.length; i++) {
        infixTokens.push(operand[i]);
        if (i < operator.length) {
            infixTokens.push(operator[i]);
        }
    }

    // Shunting-yard algorithm to convert to postfix
    const precedence = {
        '+': 1,
        '-': 1,
        '*': 2,
        '/': 2,
        '//': 2,
        '**': 3
    };

    const associativity = {
        '+': 'left',
        '-': 'left',
        '*': 'left',
        '/': 'left',
        '//': 'left',
        '**': 'right'
    };

    const outputQueue = [];
    const operatorStack = [];

    for (const token of infixTokens) {
        if (typeof token === 'number') {
            outputQueue.push(token);
        } else if (token in precedence) {
            while (
                operatorStack.length > 0 &&
                operatorStack[operatorStack.length - 1] !== '(' &&
                ((associativity[token] === 'left' && precedence[token] <= precedence[operatorStack[operatorStack.length - 1]]) ||
                 (associativity[token] === 'right' && precedence[token] < precedence[operatorStack[operatorStack.length - 1]]))
            ) {
                outputQueue.push(operatorStack.pop());
            }
            operatorStack.push(token);
        }
    }

    while (operatorStack.length > 0) {
        outputQueue.push(operatorStack.pop());
    }

    // Evaluate postfix expression
    const evalStack = [];
    for (const token of outputQueue) {
        if (typeof token === 'number') {
            evalStack.push(token);
        } else {
            const b = evalStack.pop();
            const a = evalStack.pop();
            let result;
            switch (token) {
                case '+':
                    result = a + b;
                    break;
                case '-':
                    result = a - b;
                    break;
                case '*':
                    result = a * b;
                    break;
                case '//':
                    // Floor division: Math.floor(a / b)
                    // Note: In Python, floor division rounds towards negative infinity.
                    // Math.floor in JS also rounds towards negative infinity.
                    result = Math.floor(a / b);
                    break;
                case '**':
                    result = Math.pow(a, b);
                    break;
            }
            evalStack.push(result);
        }
    }

    return evalStack[0];
}
