    const hasLetter = /[a-zA-Z]/.test(s);

    if (!hasLetter) {
        return s.split('').reverse().join('');
    }

    let result = '';
    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (char >= 'a' && char <= 'z') {
            result += char.toUpperCase();
        } else if (char >= 'A' && char <= 'Z') {
            result += char.toLowerCase();
        } else {
            result += char;
        }
    }

    return result;
}
