function parse_nested_parens(paren_string) {
    const groups = paren_string.split(' ').filter(group => group.length > 0);
    return groups.map(group => {
        let maxDepth = 0;
        let currentDepth = 0;
        for (const char of group) {
            if (char === '(') {
                currentDepth++;
                if (currentDepth > maxDepth) {
                    maxDepth = currentDepth;
                }
            } else if (char === ')') {
                currentDepth--;
            }
        }
        return maxDepth;
    });
}
