function find_closest_elements(numbers) {
    let minDiff = Infinity;
    let result = [null, null];

    for (let i = 0; i < numbers.length; i++) {
        for (let j = i + 1; j < numbers.length; j++) {
            const diff = Math.abs(numbers[i] - numbers[j]);
            if (diff < minDiff) {
                minDiff = diff;
                result[0] = Math.min(numbers[i], numbers[j]);
                result[1] = Math.max(numbers[i], numbers[j]);
            }
        }
    }

    return result;
}
