function factorize(n) {
    const factors = [];

    // Handle factor of 2
    while (n % 2 === 0) {
        factors.push(2);
        n /= 2;
    }

    // Handle odd factors starting from 3
    for (let i = 3; i <= Math.sqrt(n); i += 2) {
        while (n % i === 0) {
            factors.push(i);
            n /= i;
        }
    }

    // If n is still greater than 1, then it's a prime factor
    if (n > 1) {
        factors.push(n);
    }

    return factors;
}
```

