function sort_third(l) {
    // Extract elements at indices divisible by 3 (0, 3, 6, ...)
    const thirdElements = [];
    for (let i = 0; i < l.length; i += 3) {
        thirdElements.push(l[i]);
    }

    // Sort the extracted elements
    thirdElements.sort((a, b) => a - b);

    // Create a copy of the original array
    const result = [...l];

    // Place sorted elements back into their respective positions
    let j = 0;
    for (let i = 0; i < l.length; i += 3) {
        result[i] = thirdElements[j++];
    }

    return result;
}
