function modp(n, p) {
    if (p === 1n) return 0n;
    let base = BigInt(2);
    let exp = BigInt(n);
    let modulus = BigInt(p);
    let result = 1n;

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            result = (result * base) % modulus;
        }
        base = (base * base) % modulus;
        exp = exp / 2n;
    }

    return Number(result);
}
