function fruit_distribution(s, n) {
    // Extract the number of apples and oranges from the string
    const match = s.match(/(\d+)\s+apples?\s+and\s+(\d+)\s+oranges?/);

    if (!match) {
        return 0;
    }

    const apples = parseInt(match[1], 10);
    const oranges = parseInt(match[2], 10);

    // Calculate the number of mangoes
    const mangoes = n - (apples + oranges);

    return mangoes;
}
