```javascript
function pluck(arr) {
    if (!arr || arr.length === 0) {
        return [];
    }

    let smallestEven = Infinity;
    let smallestIndex = -1;

    for (let i = 0; i < arr.length; i++) {
        const value = arr[i];
        if (value % 2 === 0) {
            if (value < smallestEven) {
                smallestEven = value;
                smallestIndex = i;
            }
        }
    }

    if (smallestIndex === -1) {
        return [];
    }

