function starts_one_ends(n) {
    if (n === 1) {
        return 1;
    }

    // Numbers that start with 1: 1 followed by any (n-1) digits = 10^(n-1)
    const startWithOne = Math.pow(10, n - 1);

    // Numbers that end with 1: first digit can be 1-9 (but we need to avoid double counting those that both start and end with 1)
    // Actually, let's think differently:
    // Total n-digit numbers: 9 * 10^(n-1) (first digit 1-9, rest 0-9)

    // Numbers starting with 1: 1 * 10^(n-1)
    // Numbers ending with 1: first digit 1-9 (9 choices), middle n-2 digits any (10^(n-2)), last digit fixed as 1
    // So numbers ending with 1: 9 * 10^(n-2)

    // But we've double counted numbers that both start AND end with 1
    // Numbers starting and ending with 1: 1 * 10^(n-2) * 1 = 10^(n-2)

    const endWithOne = 9 * Math.pow(10, n - 2);
    const bothStartAndEndWithOne = Math.pow(10, n - 2);

    // Using inclusion-exclusion principle
    return startWithOne + endWithOne - bothStartAndEndWithOne;
}
