function sort_array(arr) {
    // Helper function to count the number of 1s in binary representation
    const countOnes = (num) => {
        let count = 0;
        let n = num;
        while (n > 0) {
            count += n & 1;
            n >>>= 1;
        }
        return count;
    };

    // Sort the array based on the number of ones in binary representation,
    // then by decimal value for ties
    return arr.slice().sort((a, b) => {
        const onesA = countOnes(a);
        const onesB = countOnes(b);
        if (onesA !== onesB) {
            return onesA - onesB;
        }
        return a - b;
    });
}
