function valid_date(date) {
    if (!date || typeof date !== 'string') {
        return false;
    }

    // Check format: mm-dd-yyyy
    const parts = date.split('-');
    if (parts.length !== 3) {
        return false;
    }

    const monthStr = parts[0];
    const dayStr = parts[1];
    const yearStr = parts[2];

    // Check that each part has the correct number of digits
    if (monthStr.length !== 2 || dayStr.length !== 2 || yearStr.length !== 4) {
        return false;
    }

    // Parse integers
    const month = parseInt(monthStr, 10);
    const day = parseInt(dayStr, 10);
    const year = parseInt(yearStr, 10);

    // Check if parsing resulted in valid numbers
    if (isNaN(month) || isNaN(day) || isNaN(year)) {
        return false;
    }

    // Rule 3: months should be between 1 and 12
    if (month < 1 || month > 12) {
        return false;
    }

    // Rule 2: days validation based on month
    let maxDays;
    if ([1, 3, 5, 7, 8, 10, 12].includes(month)) {
        maxDays = 31;
    } else if ([4, 6, 9, 11].includes(month)) {
        maxDays = 30;
    } else if (month === 2) {
        // Check for leap year
        const isLeapYear = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
        maxDays = isLeapYear ? 29 : 28;
    }

    // Rule 1: day should be between 1 and maxDays
    if (day < 1 || day > maxDays) {
        return false;
    }

    return true;
}
