function prod_signs(arr) {
    if (arr.length === 0) {
        return undefined;
    }

    // Calculate the product of signs
    let signProduct = 1;
    for (let num of arr) {
        if (num > 0) {
            signProduct *= 1;
        } else if (num < 0) {
            signProduct *= -1;
        } else {
            // If any number is 0, the product of signs is 0
            return 0;
        }
    }

    // Calculate the sum of magnitudes
    let sumMagnitudes = arr.reduce((sum, num) => sum + Math.abs(num), 0);

    return signProduct * sumMagnitudes;
}
