    }

    // We need to compute up to tri(n).
    // The recurrence for odd n depends on tri(n+1), which is a future value.
    // This suggests we might need to solve a system or compute in a specific order.
    // Let's look at the dependencies:
    // For even n: tri(n) = 1 + n/2. (Direct computation)
    // For odd n: tri(n) = tri(n-1) + tri(n-2) + tri(n+1).

    // If we want to compute tri(3), we need tri(4).
    // tri(4) is even, so tri(4) = 1 + 4/2 = 3.
    // Then tri(3) = tri(2) + tri(1) + tri(4) = 2 + 3 + 3 = 8.

    // So for any odd n, we can compute tri(n+1) first if n+1 is even (which it is), 
    // then use that to compute tri(n).

    // Strategy:
    // Compute all even indices directly.
    // Then compute odd indices from smallest to largest? Or largest to smallest?
    // Let's see: tri(3) depends on tri(4). tri(5) would depend on tri(6).
    // So if we compute evens first, we can then compute odds in increasing order.

    // Step 1: Compute all even indices up to n (or n+1 if needed for the last odd number).
    // Actually, if n is odd, we need tri(n+1) which is even. So we might need to compute up to n+1.
    // But the problem asks for first n+1 numbers, i.e., indices 0 to n.
    // So if n is odd, we need tri(n+1) as an intermediate value, but we don't return it.

    let maxIndex = n;
    if (n % 2 === 1) {
        maxIndex = n + 1; // Need to compute one more even number for the last odd calculation
    }

    // Initialize array up to maxIndex
    const triFull = new Array(maxIndex + 1);
    triFull[0] = 1;
    if (maxIndex >= 1) {
        triFull[1] = 3;
    }

    // Compute even indices
    for (let i = 2; i <= maxIndex; i += 2) {
        triFull[i] = 1 + i / 2;
    }

    // Compute odd indices from 3 to n (if n is odd, we need up to n; if n is even, we don't have any odd > 1 in the result range except possibly if we needed intermediates, but let's just compute odds up to n)
    // Wait, if n is even, do we need any odd computations? No, because the recurrence for odd n is only used if we are calculating an odd index.
    // But wait, what if n=4? We need tri(0), tri(1), tri(2), tri(3), tri(4).
    // tri(3) is odd, so we need to compute it. It depends on tri(4) which is even.
    // So yes, we might need to compute odd indices up to n if n is odd, or up to n-1 if n is even?
    // Actually, the result array has indices 0..n. So we need to compute tri(i) for all i in 0..n.

    // Let's compute odd indices from 3 up to (n if n is odd else n-1).
    const lastOdd = (n % 2 === 1) ? n : n - 1;

    for (let i = 3; i <= lastOdd; i += 2) {
        // tri(i) = tri(i-1) + tri(i-2) + tri(i+1)
        // i is odd, so i-1 is even, i-2 is odd, i+1 is even.
        // tri(i-1) and tri(i+1) are even indices, already computed.
        // tri(i-2) is an odd index less than i, so it should be already computed if we go in increasing order.
        triFull[i] = triFull[i - 1] + triFull[i - 2] + triFull[i + 1];
    }

    // Return the first n+1 elements
    return triFull.slice(0, n + 1);
}
