function is_nested(string) {
    let depth = 0;
    let maxDepth = 0;

    for (let i = 0; i < string.length; i++) {
        if (string[i] === '[') {
            depth++;
            maxDepth = Math.max(maxDepth, depth);
        } else if (string[i] === ']') {
            depth--;
            if (depth < 0) {
                // Invalid bracket sequence, reset
                depth = 0;
                maxDepth = 0;
            }
        }
    }

    // A nested bracket exists if at some point we have depth >= 2
    // This means there's a subsequence like "[[]]" where one bracket is inside another
    return maxDepth >= 2;
}
