function get_max_triples(n) {
    // Calculate the count of numbers in a that are congruent to 0, 1, or 2 mod 3
    let count0 = 0, count1 = 0, count2 = 0;

    for (let i = 1; i <= n; i++) {
        // a[i] = i*i - i + 1
        // We only care about a[i] mod 3
        let val = (i * i - i + 1) % 3;
        if (val === 0) count0++;
        else if (val === 1) count1++;
        else count2++;
    }

    // We need triples (i, j, k) with i < j < k such that a[i] + a[j] + a[k] ≡ 0 mod 3
    // The sum of three numbers is divisible by 3 if their residues mod 3 sum to 0 or 3 or 6.
    // Possible combinations of residues (r1, r2, r3) where r1+r2+r3 ≡ 0 mod 3:
    // (0, 0, 0), (1, 1, 1), (2, 2, 2), (0, 1, 2)

    let triples = 0;

    // Choose 3 from count0
    if (count0 >= 3) {
        triples += count0 * (count0 - 1) * (count0 - 2) / 6;
    }

    // Choose 3 from count1
    if (count1 >= 3) {
        triples += count1 * (count1 - 1) * (count1 - 2) / 6;
    }

    // Choose 3 from count2
    if (count2 >= 3) {
        triples += count2 * (count2 - 1) * (count2 - 2) / 6;
    }

    // Choose one from each: count0, count1, count2
    triples += count0 * count1 * count2;

    return triples;
}
