function do_algebra(operator, operand) {
    // We need to evaluate the expression respecting operator precedence.
    // Operators: +, -, *, //, **
    // Precedence (highest to lowest): **, *, //, +, -

    // Create a copy of operands and operators to work with
    let ops = [...operator];
    let nums = [...operand];

    // Helper function to perform floor division for negative numbers correctly
    const floorDiv = (a, b) => {
        if (b === 0) throw new Error("Division by zero");
        // JavaScript's Math.floor(a/b) works for positive, but for negative it rounds toward -Infinity
        // which is what we want for "floor division" in Python style.
        return Math.floor(a / b);
    };

    // We'll use a two-pass approach or a stack-based evaluation to handle precedence.
    // Let's implement a simple shunting-yard algorithm or just process by precedence levels.

    // Process exponentiation first (right-associative)
    let i = 0;
    while (i < ops.length) {
        if (ops[i] === '**') {
            nums[i] = Math.pow(nums[i], nums[i + 1]);
            nums.splice(i + 1, 1);
            ops.splice(i, 1);
            // Don't increment i, check again at same position for right-associativity? 
            // Actually, since we're going left to right and replacing, let's just continue.
            // For right associativity like 2**3**2 = 2**(3**2) = 512, we should process from right to left.
        } else {
            i++;
        }
    }

    // Now process multiplication and floor division (left-associative)
    i = 0;
    while (i < ops.length) {
        if (ops[i] === '*' || ops[i] === '//') {
            let result;
            if (ops[i] === '*') {
                result = nums[i] * nums[i + 1];
            } else {
                result = floorDiv(nums[i], nums[i + 1]);
            }
            nums[i] = result;
            nums.splice(i + 1, 1);
            ops.splice(i, 1);
            // Don't increment i to handle consecutive same-precedence operators left-to-right
        } else {
            i++;
        }
    }

    // Now process addition and subtraction (left-associative)
    i = 0;
    while (i < ops.length) {
        if (ops[i] === '+' || ops[i] === '-') {
            let result;
            if (ops[i] === '+') {
                result = nums[i] + nums[i + 1];
            } else {
                result = nums[i] - nums[i + 1];
            }
            nums[i] = result;
            nums.splice(i + 1, 1);
            ops.splice(i, 1);
        } else {
            i++;
        }
    }

    return nums[0];
}
