function factorize(n) {
    const factors = [];

    // Handle divisibility by 2
    while (n % 2 === 0) {
        factors.push(2);
        n /= 2;
    }

    // Handle odd factors starting from 3
    for (let i = 3; i <= Math.sqrt(n); i += 2) {
        while (n % i === 0) {
            factors.push(i);
            n /= i;
        }
    }

    // If n is a prime number greater than 2
    if (n > 2) {
        factors.push(n);
    }

    return factors;
}
