function modp(n, p) {
    if (p === 1n) return 0n;

    // Use BigInt for large number safety
    const bigN = BigInt(n);
    const bigP = BigInt(p);

    // Compute 2^n % p using modular exponentiation
    let base = 2n;
    let exp = bigN;
    let result = 1n;
    const mod = bigP;

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            result = (result * base) % mod;
        }
        exp = exp / 2n;
        base = (base * base) % mod;
    }

    return Number(result);
}
