function circular_shift(x, shift) {
    const digits = String(Math.abs(x));
    const n = digits.length;

    if (shift > n) {
        return digits.split('').reverse().join('');
    }

    // Right circular shift by shift positions
    const effectiveShift = shift % n;
    if (effectiveShift === 0) {
        return digits;
    }

    // Right shift: last 'effectiveShift' digits move to the front
    const shifted = digits.slice(n - effectiveShift) + digits.slice(0, n - effectiveShift);
    return shifted;
}
