function starts_one_ends(n) {
    if (n === 1) {
        return 1;
    }

    // Numbers that start with 1: 1 followed by any (n-1) digits
    // There are 10^(n-1) such numbers

    // Numbers that end with 1: any digit from 1-9 for the first position, 
    // then any (n-2) middle digits, and last digit is 1
    // There are 9 * 10^(n-2) such numbers

    // Numbers that both start AND end with 1: 1 followed by any (n-2) middle digits, then 1
    // There are 10^(n-2) such numbers

    // By inclusion-exclusion: start_with_1 + end_with_1 - both_start_and_end_with_1
    const startWithOne = Math.pow(10, n - 1);
    const endWithOne = 9 * Math.pow(10, n - 2);
    const bothStartAndEndWithOne = Math.pow(10, n - 2);

    return startWithOne + endWithOne - bothStartAndEndWithOne;
}
