function histogram(test) {
    const result = {};
    if (!test || test.trim() === '') {
        return result;
    }

    const letters = test.split(' ');
    const counts = {};

    // Count occurrences of each letter
    for (const letter of letters) {
        if (letter !== '') {
            counts[letter] = (counts[letter] || 0) + 1;
        }
    }

    // Find the maximum count
    let maxCount = 0;
    for (const letter in counts) {
        if (counts[letter] > maxCount) {
            maxCount = counts[letter];
        }
    }

    // Build result object with only letters that have the maximum count
    for (const letter in counts) {
        if (counts[letter] === maxCount) {
            result[letter] = counts[letter];
        }
    }

    return result;
