function get_closest_vowel(word) {
    if (!word || word.length < 3) {
        return "";
    }

    const vowels = new Set(['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']);

    // We need to find the closest vowel from the right side that stands between two consonants.
    // "Stands between two consonants" means the character immediately before and after the vowel are both consonants.
    // We search from right to left, so we want the first such vowel we encounter when scanning from right to left.

    // Start from index 1 (since index 0 can't have a preceding consonant) up to length-2 (since last char can't have succeeding consonant)
    for (let i = word.length - 2; i >= 1; i--) {
        const currentChar = word[i];
        const prevChar = word[i - 1];
        const nextChar = word[i + 1];

        // Check if current is a vowel
        if (vowels.has(currentChar)) {
            // Check if previous and next are consonants (i.e., letters but not vowels)
            if (!vowels.has(prevChar) && !vowels.has(nextChar)) {
                return currentChar;
            }
        }
    }

    return "";
