function valid_date(date) {
    // Rule 1: The date string is not empty.
    if (!date || typeof date !== 'string' || date.trim() === '') {
        return false;
    }

    // Rule 4: The date should be in the format: mm-dd-yyyy
    const parts = date.split('-');
    if (parts.length !== 3) {
        return false;
    }

    const monthStr = parts[0];
    const dayStr = parts[1];
    const yearStr = parts[2];

    // Check that each part consists only of digits
    if (!/^\d+$/.test(monthStr) || !/^\d+$/.test(dayStr) || !/^\d+$/.test(yearStr)) {
        return false;
    }

    const month = parseInt(monthStr, 10);
    const day = parseInt(dayStr, 10);
    const year = parseInt(yearStr, 10);

    // Rule 3: The months should not be less than 1 or higher than 12.
    if (month < 1 || month > 12) {
        return false;
    }

    // Rule 2: Validate days based on month
    let maxDays;
    switch (month) {
        case 1: case 3: case 5: case 7: case 8: case 10: case 12:
            maxDays = 31;
            break;
        case 4: case 6: case 9: case 11:
            maxDays = 30;
            break;
        case 2:
            // Check for leap year
            const isLeapYear = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
            maxDays = isLeapYear ? 29 : 28;
            break;
        default:
            return false;
    }

    if (day < 1 || day > maxDays) {
        return false;
    }

    return true;
}
