function file_name_check(file_name) {
    // Condition 2: The file's name contains exactly one dot '.'
    const dotCount = (file_name.match(/\./g) || []).length;
    if (dotCount !== 1) {
        return 'No';
    }

    const dotIndex = file_name.indexOf('.');
    const beforeDot = file_name.substring(0, dotIndex);
    const afterDot = file_name.substring(dotIndex + 1);

    // Condition 3: The substring before the dot should not be empty, and it starts with a letter
    if (beforeDot.length === 0) {
        return 'No';
    }
    if (!/^[a-zA-Z]/.test(beforeDot)) {
        return 'No';
    }

    // Condition 4: The substring after the dot should be one of these: ['txt', 'exe', 'dll']
    const validExtensions = ['txt', 'exe', 'dll'];
    if (!validExtensions.includes(afterDot)) {
        return 'No';
    }

    // Condition 1: There should not be more than three digits ('0'-'9') in the file's name.
    const digitCount = (file_name.match(/\d/g) || []).length;
    if (digitCount > 3) {
        return 'No';
    }

    return 'Yes';
