function order_by_points(nums) {
    // Helper function to calculate the sum of digits of a number
    const digitSum = (num) => {
        // Convert number to string, remove negative sign if present
        const str = num.toString().replace('-', '');
        let sum = 0;
        for (const char of str) {
            sum += parseInt(char, 10);
        }
        return sum;
    };

    // Create an array of objects with the number, its digit sum, and original index
    const items = nums.map((num, index) => ({
        num,
        sum: digitSum(num),
        index
    }));

    // Sort based on digit sum, then by original index for ties
    items.sort((a, b) => {
        if (a.sum !== b.sum) {
            return a.sum - b.sum;
        }
        return a.index - b.index;
    });

    // Extract the sorted numbers
    return items.map(item => item.num);
}
