```javascript
function get_max_triples(n) {
    // Calculate the number of elements with remainder 0, 1, 2 when divided by 3
    let count0 = 0; // a[i] % 3 == 0
    let count1 = 0; // a[i] % 3 == 1
    let count2 = 0; // a[i] % 3 == 2

    for (let i = 1; i <= n; i++) {
        let val = i * i - i + 1;
        let rem = val % 3;
        if (rem === 0) {
            count0++;
        } else if (rem === 1) {
            count1++;
        } else {
            count2++;
        }
    }

    // We need triples where a[i] + a[j] + a[k] is divisible by 3.
    // The sum of three numbers is divisible by 3 if:
    // 1. All three have remainder 0: (0, 0, 0) -> C(count0, 3)
    // 2. All three have remainder 1: (1, 1, 1) -> C(count1, 3)
    // 3. All three have remainder 2: (2, 2, 2) -> C(count2, 3)
    // 4. One of each remainder: (0, 1, 2) -> count0 * count1 * count2

    function combinations(n, k) {
        if (n < k || k < 0) return 0;
        if (k === 0 || k === n) return 1;
        if (k > n / 2) k = n - k;
        let result = 1;
        for (let i = 0; i < k; i++) {
            result = result * (n - i) / (i + 1);
        }
        return Math.round(result);
    }

    let triples = combinations(count0, 3) + 
                  combinations(count1, 3) + 
                  combinations(count2, 3) + 
                  count0 * count1 * count2;

    return triples;
}
