    if (!planets.includes(planet1) || !planets.includes(planet2)) {
        return [];
    }

    const index1 = planets.indexOf(planet1);
    const index2 = planets.indexOf(planet2);

    // If they are the same planet, return empty array
    if (index1 === index2) {
        return [];
