function make_palindrome(str) {
    if (str === "") return "";

    // Find the longest palindromic suffix of str
    let n = str.length;
    let longestPalSuffixStart = 0;

    for (let i = 0; i < n; i++) {
        // Check if substring from i to end is a palindrome
        let sub = str.substring(i);
        if (isPalindrome(sub)) {
            longestPalSuffixStart = i;
            break;
        }
    }

    // The prefix that comes before the palindromic suffix
    let prefix = str.substring(0, longestPalSuffixStart);
    let reversedPrefix = prefix.split('').reverse().join('');

    return str + reversedPrefix;
}

function isPalindrome(s) {
    let left = 0;
    let right = s.length - 1;
    while (left < right) {
        if (s[left] !== s[right]) return false;
        left++;
        right--;
    }
    return true;
}
