```javascript
function is_multiply_prime(a) {
    if (a < 2) return false;

    // Helper function to check if a number is prime
    function isPrime(n) {
        if (n < 2) return false;
        for (let i = 2; i <= Math.sqrt(n); i++) {
            if (n % i === 0) return false;
        }
        return true;
    }

    // Find the first prime factor
    let count = 0;
    let temp = a;

    for (let i = 2; i <= Math.sqrt(temp); i++) {
        if (temp % i === 0 && isPrime(i)) {
            count++;
            temp /= i;
            // Check if the remaining part is also prime and we have exactly 3 factors total
            // We need to continue factoring temp
            break;
        }
    }

    // If no factor found up to sqrt, check if temp itself is prime (meaning a was prime)
    if (count === 0) {
        return false; // a is prime or 1, not product of 3 primes
    }

    // Now temp has been divided by the first prime factor. 
    // We need to find two more prime factors for temp such that total count is 3.
    // Actually, let's just fully factorize and count prime factors.

    count = 0;
    temp = a;

    for (let i = 2; i * i <= temp; i++) {
        while (temp % i === 0) {
            if (isPrime(i)) {
                count++;
            }
            temp /= i;
        }
    }
    if (temp > 1 && isPrime(temp)) {
        count++;
    }

    return count === 3;
}
