function minPath(grid, k) {
    const N = grid.length;

    // Find the position of each value for quick lookup if needed, 
    // but primarily we need to explore paths.

    // Since we want the lexicographically smallest path of length k,
    // we can use a BFS-like approach or Dijkstra-like with state (row, col, step)
    // but the "cost" is the sequence itself.

    // However, k can be large, so we cannot store all paths.
    // We need to build the path step by step.

    // Step 1: Find the starting cell with the minimum value.
    // But wait, the first element of the path is just the value of the starting cell.
    // To minimize lexicographically, we want the smallest possible first element.
    // So we should start at the cell with the global minimum value? 
    // Not necessarily, because the subsequent elements matter too.
    // Actually, yes: if we have two paths A and B, and A[0] < B[0], then A < B regardless of what follows.
    // So the first element must be the smallest value in the grid.

    let minVal = Infinity;
    let startPositions = [];
    for (let r = 0; r < N; r++) {
        for (let c = 0; c < N; c++) {
            if (grid[r][c] < minVal) {
                minVal = grid[r][c];
                startPositions = [[r, c]];
            } else if (grid[r][c] === minVal) {
                startPositions.push([r, c]);
            }
        }
    }

    // Now we have the first element of our path: minVal.
    // We need to find the next k-1 elements.
    // At each step, from all current possible positions (which form a set of cells),
    // we look at all neighbors of these cells, and pick the one(s) with the smallest value.
    // Then we update our set of possible positions to those neighbors that have that smallest value.

    let currentPositions = startPositions; // Array of [r, c]
    let result = [minVal];

    for (let step = 1; step < k; step++) {
        let nextMinVal = Infinity;
        let nextPositions = [];

        // Collect all neighbors of current positions
        const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

        for (const [r, c] of currentPositions) {
            for (const [dr, dc] of directions) {
                const nr = r + dr;
                const nc = c + dc;
                if (nr >= 0 && nr < N && nc >= 0 && nc < N) {
                    const val = grid[nr][nc];
                    if (val < nextMinVal) {
                        nextMinVal = val;
                        nextPositions = [[nr, nc]];
                    } else if (val === nextMinVal) {
                        nextPositions.push([nr, nc]);
                    }
                }
            }
        }

        // Remove duplicates from nextPositions to avoid redundant work
        const seen = new Set();
        const uniqueNextPositions = [];
        for (const [r, c] of nextPositions) {
            const key = `${r},${c}`;
            if (!seen.has(key)) {
                seen.add(key);
                uniqueNextPositions.push([r, c]);
            }
        }

        result.push(nextMinVal);
        currentPositions = uniqueNextPositions;
    }

    return result;
}
