```javascript
function separate_paren_groups(paren_string) {
    // Remove all spaces from the input string
    const cleaned = paren_string.replace(/\s+/g, '');

    const result = [];
    let currentGroup = '';
    let depth = 0;

    for (let i = 0; i < cleaned.length; i++) {
        const char = cleaned[i];

        if (char === '(') {
            depth++;
            currentGroup += char;
        } else if (char === ')') {
            depth--;
            currentGroup += char;

            // When depth returns to 0, we've completed a balanced group
            if (depth === 0) {
                result.push(currentGroup);
                currentGroup = '';
            }
        }
    }

    return result;
}
