function mean_absolute_deviation(numbers) {
    const n = numbers.length;
    if (n === 0) return 0;

    const sum = numbers.reduce((a, b) => a + b, 0);
    const mean = sum / n;

    const absDiffs = numbers.map(x => Math.abs(x - mean));
    const mad = absDiffs.reduce((a, b) => a + b, 0) / n;

    return mad;
}
