function make_palindrome(string) {
    if (string === "") return "";

    // Find the longest palindromic suffix of the string.
    // We iterate from the end to find the longest substring starting at some index i
    // such that string[i..end] is a palindrome.
    let bestStart = 0;
    for (let i = 0; i < string.length; i++) {
        const suffix = string.substring(i);
        if (isPalindrome(suffix)) {
            bestStart = i;
            break; // Since we want the longest, and we're going from left to right in terms of start index,
                   // the first one we find is the longest? No, wait.
                   // We want the longest palindromic suffix. A suffix starting at index 0 is the whole string.
                   // If the whole string is a palindrome, that's the longest.
                   // So we should check from i=0 upwards and take the first match? 
                   // Actually, if string[0..end] is a palindrome, it's the longest possible suffix (the whole string).
                   // So yes, iterating from i=0 to end, the first i where string[i..end] is a palindrome gives the longest palindromic suffix.
            break;
        }
    }

    // The prefix that comes before the palindromic suffix is string[0..bestStart-1]
    const prefix = string.substring(0, bestStart);
    const reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}

function isPalindrome(s) {
    let left = 0;
    let right = s.length - 1;
    while (left < right) {
        if (s[left] !== s[right]) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}
