function find_closest_elements(numbers) {
    // Sort the array to easily find the closest elements
    const sorted = [...numbers].sort((a, b) => a - b);

    let minDiff = Infinity;
    let result = [sorted[0], sorted[1]];

    for (let i = 0; i < sorted.length - 1; i++) {
        const diff = Math.abs(sorted[i + 1] - sorted[i]);
        if (diff < minDiff) {
            minDiff = diff;
            result = [sorted[i], sorted[i + 1]];
        }
    }

    return result;
}

