function sort_third(l) {
    // Extract elements at indices divisible by 3 (0, 3, 6, ...)
    const thirdIndices = [];
    for (let i = 0; i < l.length; i += 3) {
        thirdIndices.push(i);
    }

    // Get the values at those indices and sort them
    const sortedValues = thirdIndices.map(i => l[i]).sort((a, b) => a - b);

    // Create a copy of the original array
    const result = [...l];

    // Replace the values at the third indices with the sorted values
    for (let j = 0; j < thirdIndices.length; j++) {
        result[thirdIndices[j]] = sortedValues[j];
    }

    return result;
}
