function prime_fib(n) {
    // Generate Fibonacci numbers and check if they are prime
    // We need to find the n-th number that is both a Fibonacci number and prime

    // Helper function to check if a number is prime
    function isPrime(num) {
        if (num < 2) return false;
        if (num === 2) return true;
        if (num % 2 === 0) return false;
        for (let i = 3; i <= Math.sqrt(num); i += 2) {
            if (num % i === 0) return false;
        }
        return true;
    }

    // Generate Fibonacci numbers and collect those that are prime
    let count = 0;
    let a = 0, b = 1;

    while (count < n) {
        let fib = a;
        a = b;
        b = a + fib;

        if (isPrime(fib)) {
            count++;
            if (count === n) {
                return fib;
            }
        }
    }
}
