function modp(n, p) {
    if (p === 1n) return 0n;
    let base = BigInt(2);
    let exp = BigInt(n);
    let result = 1n;
    const mod = BigInt(p);

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            result = (result * base) % mod;
        }
        exp = exp / 2n;
        base = (base * base) % mod;
    }

    return Number(result);
}
