function circular_shift(x, shift) {
    const str = String(x);
    const len = str.length;

    if (shift > len) {
        return str.split('').reverse().join('');
    }

    // Normalize shift to be within [0, len)
    const effectiveShift = shift % len;

    // Right circular shift by effectiveShift
    // Right shift by 1: last char moves to front
    // e.g., "1234" right shift 1 -> "4123"
    // Split at index (len - effectiveShift)
    const splitIndex = len - effectiveShift;
    const rightPart = str.slice(splitIndex);
    const leftPart = str.slice(0, splitIndex);

    return rightPart + leftPart;
}
