```javascript
function starts_one_ends(n) {
    if (n === 1) {
        return 1;
    }
    // Numbers that start with 1: first digit is 1, remaining n-1 digits can be anything (0-9)
    // Count = 1 * 10^(n-1)
    let startsWithOne = Math.pow(10, n - 1);

    // Numbers that end with 1: last digit is 1, first digit can be 1-9 (9 choices), middle n-2 digits can be anything (10^(n-2))
    // Count = 9 * 10^(n-2)
    let endsWithOne = 9 * Math.pow(10, n - 2);

    // Numbers that both start and end with 1: first digit is 1, last digit is 1, middle n-2 digits can be anything (10^(n-2))
    // Count = 1 * 10^(n-2) * 1 = 10^(n-2)
    let bothStartAndEndWithOne = Math.pow(10, n - 2);

    // Use inclusion-exclusion principle
    return startsWithOne + endsWithOne - bothStartAndEndWithOne;
}
