        return [];
    }

    // Create a copy of the array to avoid mutating the original
    const sorted = [...array];

    const firstValue = sorted[0];
    const lastValue = sorted[sorted.length - 1];
    const sum = firstValue + lastValue;

    if (sum % 2 === 1) {
        // Odd sum: sort in ascending order
        sorted.sort((a, b) => a - b);
    } else {
        // Even sum: sort in descending order
        sorted.sort((a, b) => b - a);
    }

    return sorted;
}
