function valid_date(date) {
    if (!date || typeof date !== 'string') return false;

    const parts = date.split('-');
    if (parts.length !== 3) return false;

    const [monthStr, dayStr, yearStr] = parts;

    // Check format: must be exactly mm-dd-yyyy with digits only
    if (!/^\d{2}-\d{2}-\d{4}$/.test(date)) return false;

    const month = parseInt(monthStr, 10);
    const day = parseInt(dayStr, 10);
    const year = parseInt(yearStr, 10);

    // Check if parsed values are valid numbers and match the string representation (to avoid leading zeros issues like "00")
    if (isNaN(month) || isNaN(day) || isNaN(year)) return false;
    if (monthStr !== String(month).padStart(2, '0')) return false;
    if (dayStr !== String(day).padStart(2, '0')) return false;

    // Rule 3: Month must be between 1 and 12
    if (month < 1 || month > 12) return false;

    // Rule 2: Day validation based on month
    let maxDays = 0;
    if ([1, 3, 5, 7, 8, 10, 12].includes(month)) {
        maxDays = 31;
    } else if ([4, 6, 9, 11].includes(month)) {
        maxDays = 30;
    } else if (month === 2) {
        // Check for leap year
        const isLeap = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
        maxDays = isLeap ? 29 : 28;
    }

    if (day < 1 || day > maxDays) return false;

    return true;
}
