function tri(n) {
    if (n === 0) return [1];

    const result = [];
    // tri(1) = 3, but the example shows tri(3) returns [1, 3, 2, 8]
    // Let me re-read: "first n + 1 numbers"
    // Example: tri(3) returns [1, 3, 2, 8] which has 4 elements (indices 0 to 3)
    // So index 0 seems to be 1? But the definition says tri(1) = 3.
    // Let me check: tri(2) = 2, tri(4) = 3, tri(3) = 8
    // The array [1, 3, 2, 8] corresponds to tri(0)=1?, tri(1)=3, tri(2)=2, tri(3)=8

    // It seems like tri(0) = 1 is implied or the sequence starts at index 0 with value 1.
    // Let me verify: if tri(0) = 1, then for n=3 we get [tri(0), tri(1), tri(2), tri(3)] = [1, 3, 2, 8]

    // Define the sequence with tri(0) = 1
    result[0] = 1;
    result[1] = 3;

    for (let i = 2; i <= n; i++) {
        if (i % 2 === 0) {
            // even: tri(n) = 1 + n / 2
            result[i] = 1 + i / 2;
        } else {
            // odd: tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
            // But tri(n+1) is not yet computed! This is a problem.
            // Let me re-read the recurrence for odd n.
            // tri(n) = tri(n - 1) + tri(n - 2) + tri(n + 1), if n is odd.
            // For n=3 (odd): tri(3) = tri(2) + tri(1) + tri(4)
            // We need tri(4) to compute tri(3). But tri(4) is even, so tri(4) = 1 + 4/2 = 3.
            // So tri(3) = 2 + 3 + 3 = 8. That works if we can compute tri(4) first.

            // This means for odd n, we need tri(n+1) which is even and can be computed directly.
            const triNPlus1 = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + triNPlus1;
        }
    }

    return result.slice(0, n + 1);
}
