function simplify(x, n) {
    // Parse x and n into numerators and denominators
    const [xNum, xDen] = x.split('/').map(Number);
    const [nNum, nDen] = n.split('/').map(Number);

    // Compute the product: (xNum * nNum) / (xDen * nDen)
    const productNum = xNum * nNum;
    const productDen = xDen * nDen;

    // Check if the result is a whole number
    // A fraction a/b is a whole number if a % b === 0
    return productNum % productDen === 0;
}
